package com.example.sharehandler

import android.content.Intent
import android.graphics.Bitmap
import android.net.Uri
import android.os.Bundle
import android.provider.MediaStore
import android.util.Log
import androidx.appcompat.app.AppCompatActivity
import java.io.ByteArrayOutputStream
import java.io.IOException

class ShareHandlerActivity : AppCompatActivity() {
    private val TAG = "ShareHandlerActivity"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        val intent = intent
        val action = intent.action
        val type = intent.type
        
        if (Intent.ACTION_SEND == action && type != null) {
            if (type.startsWith("text/")) {
                handleTextShare(intent)
            } else if (type.startsWith("image/")) {
                handleImageShare(intent)
            }
        }
        
        finish()
    }
    
    private fun handleTextShare(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        if (sharedText != null) {
            Log.d(TAG, "Received shared text: $sharedText")
            // Process the shared text URL
            processSharedContent(sharedText)
        }
    }
    
    private fun handleImageShare(intent: Intent) {
        val uri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        if (uri != null) {
            try {
                val bitmap = MediaStore.Images.Media.getBitmap(contentResolver, uri)
                Log.d(TAG, "Received shared image")
                // Process the shared image
                processSharedImage(bitmap)
            } catch (e: IOException) {
                Log.e(TAG, "Error processing shared image", e)
            }
        }
    }
    
    private fun processSharedContent(content: String) {
        // Extract URL from text if it's a URL
        val urlRegex = Regex("https?://[\\w\\-]+(\\.[\\w\\-]+)+([\\w\\-\\.,@?^=%&:/~\\+#]*[\\w\\-@?^=%&/~\\+#])?")
        val urls = urlRegex.findAll(content)
        
        urls.forEach { match ->
            val url = match.value
            Log.d(TAG, "Extracted URL: $url")
            // Process the URL here
        }
    }
    
    private fun processSharedImage(bitmap: Bitmap) {
        // Convert bitmap to byte array for processing
        val baos = ByteArrayOutputStream()
        bitmap.compress(Bitmap.CompressFormat.PNG, 100, baos)
        val imageBytes = baos.toByteArray()
        Log.d(TAG, "Processing shared image with ${imageBytes.size} bytes")
        // Process the image bytes here
    }
}